class RedirectURIValidationError(Exception):
    """Raised when a redirect URI fails security validation."""
    pass


def validate_redirect_uri_secure(redirect_uri: str, allowed_domain: str) -> bool:
    """
    Securely validate that a redirect URI belongs to the allowed domain.

    SECURITY NOTE: We do NOT use `if domain in redirect_uri` because substring
    matching is vulnerable to bypass attacks such as:
      - https://evil.com?example.com  (domain in query string)
      - https://example.com.evil.com  (attacker-controlled subdomain)
      - https://notexample.com        (partial match)

    Instead, we:
      1. Parse the URL properly
      2. Enforce HTTPS
      3. Extract the hostname
      4. Check that the hostname exactly matches or is a legitimate subdomain
         using a suffix check with a dot boundary
    """
    if not redirect_uri or not allowed_domain:
        return False

    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        logger.warning("Failed to parse redirect_uri: %s", redirect_uri)
        return False

    # 1. Enforce HTTPS only
    if parsed.scheme != "https":
        logger.warning(
            "Redirect URI scheme is not HTTPS: %s (scheme=%s)",
            redirect_uri, parsed.scheme
        )
        return False

    # 2. Ensure there's a valid hostname
    hostname = parsed.hostname
    if not hostname:
        logger.warning("No hostname found in redirect_uri: %s", redirect_uri)
        return False

    # 3. Normalize to lowercase
    hostname = hostname.lower()
    allowed_domain = allowed_domain.lower()

    # 4. Reject if hostname contains userinfo (e.g., user@host) — urlparse handles
    #    this but we double check there's no '@' in netloc
    if "@" in parsed.netloc:
        logger.warning("Redirect URI contains userinfo component: %s", redirect_uri)
        return False

    # 5. Reject URIs with port numbers that could be used to redirect to
    #    attacker services on non-standard ports (optional strictness)
    if parsed.port is not None and parsed.port not in (443,):
        logger.warning(
            "Redirect URI uses non-standard port %d: %s", parsed.port, redirect_uri
        )
        return False

    # 6. Check exact match or proper subdomain match with dot boundary
    #    This prevents "evil-example.com" from matching "example.com"
    if hostname == allowed_domain:
        return True
    if hostname.endswith("." + allowed_domain):
        return True

    logger.warning(
        "Redirect URI hostname '%s' does not match allowed domain '%s'",
        hostname, allowed_domain
    )
    return False


