def generate_pkce_pair():
    """Generate PKCE code_verifier and code_challenge (S256)."""
    code_verifier = base64.urlsafe_b64encode(secrets.token_bytes(32)).rstrip(b"=").decode("ascii")
    code_challenge = (
        base64.urlsafe_b64encode(hashlib.sha256(code_verifier.encode("ascii")).digest())
        .rstrip(b"=")
        .decode("ascii")
    )
    return code_verifier, code_challenge


def get_tenant_config(tenant_id: str) -> dict:
    """Retrieve and validate tenant configuration."""
    if tenant_id not in TENANTS:
        abort(404, description=f"Unknown tenant: {tenant_id}")
    return TENANTS[tenant_id]


def require_authenticated(f):
    """Decorator to require an authenticated session."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if "access_token" not in session:
            return jsonify({"error": "not_authenticated", "message": "Please log in first"}), 401
        return f(*args, **kwargs)
    return decorated


