@app.route("/login/<tenant_id>")
def login(tenant_id: str):
    """
    Initiate OAuth 2.0 Authorization Code flow with PKCE for a given tenant.
    """
    config = get_tenant_config(tenant_id)
    redirect_uri = config["redirect_uri"]
    allowed_domain = config["allowed_domain"]

    # --- SECURE redirect_uri validation ---
    if not validate_redirect_uri_secure(redirect_uri, allowed_domain):
        logger.error(
            "Redirect URI validation failed for tenant '%s': uri='%s', domain='%s'",
            tenant_id, redirect_uri, allowed_domain,
        )
        return jsonify({
            "error": "invalid_redirect_uri",
            "message": "The configured redirect URI is invalid for this tenant.",
        }), 400

    # Generate state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)

    # Generate PKCE parameters
    code_verifier, code_challenge = generate_pkce_pair()

    # Store in session for validation on callback
    session["oauth_state"] = state
    session["oauth_tenant_id"] = tenant_id
    session["oauth_code_verifier"] = code_verifier
    session["oauth_redirect_uri"] = redirect_uri

    # Build authorization URL
    params = {
        "response_type": "code",
        "client_id": config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": config["scopes"],
        "state": state,
        "code_challenge": code_challenge,
        "code_challenge_method": "S256",
    }

    authorization_url = f"{config['authorization_endpoint']}?{urlencode(params)}"

    logger.info("Redirecting tenant '%s' to authorization endpoint", tenant_id)
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    """
    OAuth 2.0 callback endpoint. Exchanges authorization code for tokens.
    """
    # Validate state to prevent CSRF
    received_state = request.args.get("state")
    expected_state = session.pop("oauth_state", None)

    if not received_state or not expected_state:
        logger.warning("Missing state parameter in callback")
        return jsonify({"error": "missing_state"}), 400

    if not secrets.compare_digest(received_state, expected_state):
        logger.warning("State mismatch in callback — possible CSRF attack")
        return jsonify({"error": "state_mismatch", "message": "Invalid state parameter"}), 400

    # Check for error response from authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "No description provided")
        logger.warning("Authorization error: %s — %s", error, error_description)
        return jsonify({
            "error": error,
            "error_description": error_description,
        }), 400

    # Extract authorization code
    code = request.args.get("code")
    if not code:
        logger.warning("No authorization code in callback")
        return jsonify({"error": "missing_code"}), 400

    # Retrieve session data
    tenant_id = session.pop("oauth_tenant_id", None)
    code_verifier = session.pop("oauth_code_verifier", None)
    stored_redirect_uri = session.pop("oauth_redirect_uri", None)

    if not tenant_id or not code_verifier or not stored_redirect_uri:
        logger.warning("Missing session data in callback")
        return jsonify({"error": "invalid_session"}), 400

    config = get_tenant_config(tenant_id)

    # Exchange authorization code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": stored_redirect_uri,
        "client_id": config["client_id"],
        "client_secret": config["client_secret"],
        "code_verifier": code_verifier,
    }

    try:
        token_response = requests.post(
            config["token_endpoint"],
            data=token_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.exceptions.RequestException as e:
        logger.error("Token exchange failed for tenant '%s': %s", tenant_id, e)
        return jsonify({
            "error": "token_exchange_failed",
            "message": "Failed to exchange authorization code for tokens",
        }), 502

    # Store tokens in session
    session["access_token"] = tokens.get("access_token")
    session["refresh_token"] = tokens.get("refresh_token")
    session["id_token"] = tokens.get("id_token")
    session["token_type"] = tokens.get("token_type")
    session["tenant_id"] = tenant_id

    logger.info("Successfully authenticated for tenant '%s'", tenant_id)

    return redirect("/profile")


@app.route("/profile")
@require_authenticated
def profile():
    """Fetch and display user profile from the userinfo endpoint."""
    tenant_id = session.get("tenant_id")
    config = get_tenant_config(tenant_id)
    access_token = session.get("access_token")

    try:
        userinfo_response = requests.get(
            config["userinfo_endpoint"],
            headers={
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            },
            timeout=10,
        )
        userinfo_response.raise_for_status()
        userinfo = userinfo_response.json()
    except requests.exceptions.RequestException as e:
        logger.error("Failed to fetch userinfo for tenant '%s': %s", tenant_id, e)
        return jsonify({"error": "userinfo_failed"}), 502

    return jsonify({
        "tenant_id": tenant_id,
        "userinfo": userinfo,
    })


